import {
  Box,
  IconButton,
  SxProps,
  TableCell,
  TableRow,
  Theme,
  Tooltip,
} from "@mui/material";
import { type ReactNode, useCallback, useState } from "react";

import type { TransactionDirection } from "@dfp/bw-isomorphic-enums";
import { IconChevronDown } from "@dfp/react-icons";
import { createCheckedContext } from "@dfp/react-utils";

import { useTT } from "../../../useTT.ts";
import { useSelectedColumn } from "../../SelectionContext.tsx";
import { cashflowLayoutConfig } from "../../cashflow-layout.config.ts";
import type { CategoryType } from "../types/index.ts";
import { useOpenCategoryDetail } from "./categoryDetail/index.ts";

type CashflowCategoryContextValue = {
  isExpanded: boolean;
  toggleExpanded: () => void;
};

const [CashflowCategoryProvider, useCashflowCategory] =
  createCheckedContext<CashflowCategoryContextValue>("CashflowCategoryContext");

type CashflowCategoryProps = {
  children: ReactNode;
  defaultExpanded?: boolean;
};

export function CashflowCategory({
  children,
  defaultExpanded = true,
}: CashflowCategoryProps) {
  const [isExpanded, setIsExpanded] = useState(defaultExpanded);

  const toggleExpanded = () => setIsExpanded((prev) => !prev);

  return (
    <CashflowCategoryProvider value={{ isExpanded, toggleExpanded }}>
      {children}
    </CashflowCategoryProvider>
  );
}

type CashflowCategoryHeaderProps = {
  children: ReactNode;
};

export function CashflowCategoryHeader({
  children,
}: CashflowCategoryHeaderProps) {
  return <TableRow>{children}</TableRow>;
}

type CashflowCategoryHeaderTitleProps = {
  children: ReactNode;
};

export function CashflowCategoryHeaderTitle({
  children,
}: CashflowCategoryHeaderTitleProps) {
  return (
    <TableCell
      sx={{
        backgroundColor: "background.paper",
        borderRight: 1,
        borderRightColor: "custom.borderSecondary",
        fontWeight: 600,
        width: cashflowLayoutConfig.labelColumnWidth,
        boxSizing: "border-box",
      }}
    >
      <Box sx={{ display: "flex", alignItems: "center", gap: 1 }}>
        {children}
      </Box>
    </TableCell>
  );
}

type CashflowCategoryHeaderIconProps = {
  children: ReactNode;
  sx: SxProps<Theme>;
};

export function CashflowCategoryHeaderIcon({
  children,
  sx,
}: CashflowCategoryHeaderIconProps) {
  return (
    <Box
      component="span"
      sx={{
        fontSize: "1.2em",
        ...sx,
      }}
    >
      {children}
    </Box>
  );
}

type CashflowCategoryRowProps = {
  children: ReactNode;
};

export function CashflowCategoryRow({ children }: CashflowCategoryRowProps) {
  return <TableRow>{children}</TableRow>;
}

type CashflowCategoryRowLabelProps = {
  children: ReactNode;
  category: CategoryType;
  direction: TransactionDirection;
};

export function CashflowCategoryRowLabel({
  children,
  category,
  direction,
}: CashflowCategoryRowLabelProps) {
  const selectedColumn = useSelectedColumn();

  const openDetail = useOpenCategoryDetail({
    category,
    direction,
    categoryLabel: children,
  });

  const handleClick = useCallback(() => {
    if (selectedColumn == null) return;
    openDetail(selectedColumn);
  }, [selectedColumn, openDetail]);

  return (
    <TableCell
      onClick={handleClick}
      sx={{
        backgroundColor: "background.paper",
        borderRight: 1,
        borderRightColor: "custom.borderSecondary",
        paddingLeft: 4,
        width: cashflowLayoutConfig.labelColumnWidth,
        minWidth: cashflowLayoutConfig.labelColumnWidth,
        maxWidth: cashflowLayoutConfig.labelColumnWidth,
        boxSizing: "border-box",
        cursor: "pointer",
      }}
    >
      <Tooltip title={children} placement="top-start">
        <Box
          component="span"
          sx={{
            display: "block",
            overflow: "hidden",
            textOverflow: "ellipsis",
            whiteSpace: "nowrap",
            "&:hover": {
              textDecoration: "underline",
            },
          }}
        >
          {children}
        </Box>
      </Tooltip>
    </TableCell>
  );
}

type CashflowCategoryTriggerProps = {
  categoryType: "income" | "costs";
};

export function CashflowCategoryTrigger({
  categoryType,
}: CashflowCategoryTriggerProps) {
  const { isExpanded, toggleExpanded } = useCashflowCategory();
  const { tt } = useTT();

  const ariaLabel = isExpanded
    ? tt(
        categoryType === "income"
          ? "cashflowTable.accessibility.collapseIncome"
          : "cashflowTable.accessibility.collapseCosts",
      )
    : tt(
        categoryType === "income"
          ? "cashflowTable.accessibility.expandIncome"
          : "cashflowTable.accessibility.expandCosts",
      );

  return (
    <IconButton
      size="small"
      onClick={toggleExpanded}
      aria-expanded={isExpanded}
      aria-label={ariaLabel}
      sx={{
        ml: "auto",
        transform: isExpanded ? "rotate(180deg)" : "rotate(0deg)",
        transition: "transform 0.2s",
      }}
    >
      <IconChevronDown />
    </IconButton>
  );
}

type CashflowCategoryRowsProps = {
  children: ReactNode;
};

export function CashflowCategoryRows({ children }: CashflowCategoryRowsProps) {
  const { isExpanded } = useCashflowCategory();

  return isExpanded ? <>{children}</> : null;
}

import { TableCell, TableRow } from "@mui/material";
import { ReactNode } from "react";

import { cashflowLayoutConfig } from "../../cashflow-layout.config.ts";

type CashflowTableSummaryRowProps = {
  children: ReactNode;
};

export function CashflowTableSummaryRow({
  children,
}: CashflowTableSummaryRowProps) {
  return <TableRow>{children}</TableRow>;
}

type CashflowTableSummaryRowLabelProps = {
  children: ReactNode;
};

export function CashflowTableSummaryRowLabel({
  children,
}: CashflowTableSummaryRowLabelProps) {
  return (
    <TableCell
      sx={{
        backgroundColor: "background.paper",
        borderRight: 1,
        borderRightColor: "custom.borderSecondary",
        fontWeight: 600,
        width: cashflowLayoutConfig.labelColumnWidth,
        boxSizing: "border-box",
      }}
    >
      {children}
    </TableCell>
  );
}

