import {
  Box,
  IconButton,
  TableCell,
  TableRow,
  Tooltip,
  type SxProps,
  type Theme,
} from "@mui/material";
import dayjs from "dayjs";
import {
  type ReactNode,
  createContext,
  memo,
  useCallback,
  useContext,
  useMemo,
  useState,
} from "react";

import { CurrencyAmount } from "@dfp/react-currency-amount";
import { IconChevronDown } from "@dfp/react-icons";

import { CashflowQualityIndicator } from "../../chart/components/CashflowQualityIndicator.tsx";
import { useIsColumnSelected } from "../../SelectionContext.tsx";
import { useTimePeriodControls } from "../../TimePeriodContext.tsx";
import { cashflowLayoutConfig } from "../../cashflow-layout.config.ts";
import type { BalanceQuality } from "../../types/cashflow.types.ts";
import { useTT } from "../../../useTT.ts";
import type { TransactionDirection } from "@dfp/bw-isomorphic-enums";
import { useOpenCategoryDetail } from "./categoryDetail/index.ts";

export type CashflowTableValueColorMode = "balance" | "final" | "none";

type CashflowSectionContextValue = {
  isExpanded: boolean;
  toggleExpanded: () => void;
};

const CashflowSectionContext = createContext<CashflowSectionContextValue | null>(null);

function useCashflowSection() {
  const value = useContext(CashflowSectionContext);
  if (!value) {
    throw new Error("CashflowSectionContext is missing");
  }
  return value;
}

type CashflowSectionProps = {
  children: ReactNode;
  defaultExpanded?: boolean;
};

export function CashflowSection({ children, defaultExpanded = true }: CashflowSectionProps) {
  const [isExpanded, setIsExpanded] = useState(defaultExpanded);
  const toggleExpanded = useCallback(() => setIsExpanded((prev) => !prev), []);
  const value = useMemo(() => ({ isExpanded, toggleExpanded }), [isExpanded, toggleExpanded]);

  return <CashflowSectionContext.Provider value={value}>{children}</CashflowSectionContext.Provider>;
}

type CashflowSectionHeaderProps = {
  children: ReactNode;
};

export function CashflowSectionHeader({ children }: CashflowSectionHeaderProps) {
  return <TableRow>{children}</TableRow>;
}

type CashflowSectionHeaderTitleProps = {
  children: ReactNode;
};

export function CashflowSectionHeaderTitle({ children }: CashflowSectionHeaderTitleProps) {
  return (
    <TableCell
      sx={{
        backgroundColor: "background.paper",
        borderRight: 1,
        borderRightColor: "custom.borderSecondary",
        fontWeight: 600,
        width: cashflowLayoutConfig.labelColumnWidth,
        boxSizing: "border-box",
      }}
    >
      <Box sx={{ display: "flex", alignItems: "center", gap: 1 }}>{children}</Box>
    </TableCell>
  );
}

type CashflowSectionHeaderIconProps = {
  children: ReactNode;
  sx: SxProps<Theme>;
};

export function CashflowSectionHeaderIcon({ children, sx }: CashflowSectionHeaderIconProps) {
  return (
    <Box component="span" sx={{ fontSize: "1.2em", ...sx }}>
      {children}
    </Box>
  );
}

type CashflowSectionTriggerProps = {
  categoryType: "income" | "costs";
};

export function CashflowSectionTrigger({ categoryType }: CashflowSectionTriggerProps) {
  const { isExpanded, toggleExpanded } = useCashflowSection();
  const { tt } = useTT();

  const ariaLabel = isExpanded
    ? tt(
        categoryType === "income"
          ? "cashflowTable.accessibility.collapseIncome"
          : "cashflowTable.accessibility.collapseCosts",
      )
    : tt(
        categoryType === "income"
          ? "cashflowTable.accessibility.expandIncome"
          : "cashflowTable.accessibility.expandCosts",
      );

  return (
    <IconButton
      size="small"
      onClick={toggleExpanded}
      aria-expanded={isExpanded}
      aria-label={ariaLabel}
      sx={{
        ml: "auto",
        transform: isExpanded ? "rotate(180deg)" : "rotate(0deg)",
        transition: "transform 0.2s",
      }}
    >
      <IconChevronDown />
    </IconButton>
  );
}

type CashflowSectionRowsProps = {
  children: ReactNode;
};

export function CashflowSectionRows({ children }: CashflowSectionRowsProps) {
  const { isExpanded } = useCashflowSection();
  return isExpanded ? <>{children}</> : null;
}

type CashflowSectionRowProps = {
  children: ReactNode;
};

export function CashflowSectionRow({ children }: CashflowSectionRowProps) {
  return <TableRow>{children}</TableRow>;
}

type CashflowSectionRowLabelProps = {
  children: ReactNode;
  bold?: boolean;
  interactive?: boolean;
  onClick?: () => void;
  tooltip?: ReactNode;
};

export function CashflowSectionRowLabel({
  children,
  bold = false,
  interactive = false,
  onClick,
  tooltip,
}: CashflowSectionRowLabelProps) {
  const content = (
    <TableCell
      onClick={onClick}
      sx={{
        backgroundColor: "background.paper",
        borderRight: 1,
        borderRightColor: "custom.borderSecondary",
        fontWeight: bold ? 600 : 400,
        width: cashflowLayoutConfig.labelColumnWidth,
        minWidth: cashflowLayoutConfig.labelColumnWidth,
        maxWidth: cashflowLayoutConfig.labelColumnWidth,
        boxSizing: "border-box",
        cursor: interactive ? "pointer" : undefined,
      }}
    >
      {children}
    </TableCell>
  );

  if (tooltip == null) return content;

  return <Tooltip title={tooltip}>{content}</Tooltip>;
}

type CashflowSectionValueCellProps = {
  value: number | null;
  currency?: string;
  columnIndex: number;
  dateFrom: string;
  isBold?: boolean;
  colorMode?: CashflowTableValueColorMode;
  balanceQuality?: BalanceQuality | null;
  onClick?: () => void;
};

function CashflowSectionValueCellComponent({
  value,
  currency,
  columnIndex,
  dateFrom,
  isBold = false,
  colorMode = "none",
  balanceQuality,
  onClick,
}: CashflowSectionValueCellProps) {
  const isHighlighted = useIsColumnSelected(columnIndex);
  const { setPeriod } = useTimePeriodControls();
  const handleClick = onClick ?? (() => setPeriod(dayjs(dateFrom)));

  return (
    <TableCell
      onClick={handleClick}
      aria-selected={isHighlighted}
      sx={{
        textAlign: "right",
        cursor: "pointer",
        backgroundColor: "background.paper",
        borderBottom: isHighlighted ? "none" : undefined,
        borderRight: 1,
        borderRightColor: isHighlighted ? "custom.borderSecondary" : "background.paper",
        borderLeft: 1,
        borderLeftColor: isHighlighted ? "custom.borderSecondary" : "background.paper",
        fontWeight: isBold ? 600 : 400,
        color: colorMode === "none" || value === null ? "text.primary" : "text.primary",
        boxSizing: "border-box",
      }}
    >
      <Box
        sx={{
          minHeight: 24,
          display: "flex",
          alignItems: "center",
          justifyContent: "flex-end",
          gap: 0.5,
          width: "100%",
          whiteSpace: "nowrap",
        }}
      >
        {value !== null ? (
          <>
            <CashflowQualityIndicator balanceQuality={balanceQuality} size="sm" variant="icon" />
            {currency ? (
              <CurrencyAmount notation="compact" value={value} currency={currency} naturalPrecision />
            ) : (
              value
            )}
          </>
        ) : null}
      </Box>
    </TableCell>
  );
}

export const CashflowSectionValueCell = memo(CashflowSectionValueCellComponent);
CashflowSectionValueCell.displayName = "CashflowSectionValueCell";

export {
  CashflowSection,
  CashflowSectionHeader,
  CashflowSectionHeaderIcon,
  CashflowSectionHeaderTitle,
  CashflowSectionRow,
  CashflowSectionRowLabel,
  CashflowSectionRows,
  CashflowSectionTrigger,
  CashflowSectionValueCell,
  type CashflowTableValueColorMode,
} from "./CashflowSection.tsx";
export { CashflowCategoryDataRow } from "./CashflowCategoryDataRow.tsx";
export {
  type CashflowTableContextValue,
  CashflowTableProvider,
  useCashflowTable,
} from "./CashflowTableContext.tsx";
export { CashflowTableSummaryValueCell, type CashflowTableSummaryValueCellProps } from "./CashflowTableSummaryValueCell.tsx";
