export function CashflowTableIncomeCategories() {
  const { data, categoryFilter, allCategories, currency } = useCashflowTable();
  const { tt } = useTT();

  return (
    <CashflowSection>
      <CashflowSectionHeader>
        <CashflowSectionHeaderTitle>
          <CashflowSectionHeaderIcon sx={{ color: "success.main" }}>
