      </CashflowSectionHeader>

      <CashflowSectionRows>
        {categoryFilter.income.map((category) => (
          <CashflowCategoryDataRow
            key={category}
            allCategories={allCategories}
            category={category}
            direction="IN"
          />
        ))}
      </CashflowSectionRows>
    </CashflowSection>
  );
}

