import {
  Box,
  IconButton,
  TableCell,
  TableRow,
  Tooltip,
  type SxProps,
  type Theme,
} from "@mui/material";
import dayjs from "dayjs";
import {
  type ReactNode,
  createContext,
  memo,
  useCallback,
  useContext,
  useMemo,
  useState,
} from "react";

import { CurrencyAmount } from "@dfp/react-currency-amount";
import { IconChevronDown } from "@dfp/react-icons";

import { CashflowQualityIndicator } from "../../chart/components/CashflowQualityIndicator.tsx";
import { useIsColumnSelected } from "../../SelectionContext.tsx";
import { useTimePeriodControls } from "../../TimePeriodContext.tsx";
import { cashflowLayoutConfig } from "../../cashflow-layout.config.ts";
import type { BalanceQuality } from "../../types/cashflow.types.ts";
import { useTT } from "../../../useTT.ts";

export type CashflowTableValueColorMode = "balance" | "final" | "none";

type CashflowSectionContextValue = {
  isExpanded: boolean;
  toggleExpanded: () => void;
};

const CashflowSectionContext = createContext<CashflowSectionContextValue | null>(null);

function useCashflowSection() {
  const value = useContext(CashflowSectionContext);
  if (!value) throw new Error("CashflowSectionContext is missing");
  return value;
}

type CashflowSectionProps = { children: ReactNode; defaultExpanded?: boolean };
export function CashflowSection({ children, defaultExpanded = true }: CashflowSectionProps) {
  const [isExpanded, setIsExpanded] = useState(defaultExpanded);
  const toggleExpanded = useCallback(() => setIsExpanded((prev) => !prev), []);
  const value = useMemo(() => ({ isExpanded, toggleExpanded }), [isExpanded, toggleExpanded]);
  return <CashflowSectionContext.Provider value={value}>{children}</CashflowSectionContext.Provider>;
}

export function CashflowSectionHeader({ children }: { children: ReactNode }) {
  return <TableRow>{children}</TableRow>;
}

export function CashflowSectionHeaderTitle({ children }: { children: ReactNode }) {
  return (
    <TableCell
      sx={{
        backgroundColor: "background.paper",
        borderRight: 1,
        borderRightColor: "custom.borderSecondary",
        fontWeight: 600,
        width: cashflowLayoutConfig.labelColumnWidth,
        boxSizing: "border-box",
      }}
    >
      <Box sx={{ display: "flex", alignItems: "center", gap: 1 }}>{children}</Box>
    </TableCell>
  );
}

export function CashflowSectionHeaderIcon({ children, sx }: { children: ReactNode; sx: SxProps<Theme> }) {
  return <Box component="span" sx={{ fontSize: "1.2em", ...sx }}>{children}</Box>;
}

export function CashflowSectionTrigger({ categoryType }: { categoryType: "income" | "costs" }) {
  const { isExpanded, toggleExpanded } = useCashflowSection();
  const { tt } = useTT();
  const ariaLabel = isExpanded
    ? tt(categoryType === "income" ? "cashflowTable.accessibility.collapseIncome" : "cashflowTable.accessibility.collapseCosts")
    : tt(categoryType === "income" ? "cashflowTable.accessibility.expandIncome" : "cashflowTable.accessibility.expandCosts");
  return (
    <IconButton size="small" onClick={toggleExpanded} aria-expanded={isExpanded} aria-label={ariaLabel} sx={{ ml: "auto", transform: isExpanded ? "rotate(180deg)" : "rotate(0deg)", transition: "transform 0.2s" }}>
      <IconChevronDown />
    </IconButton>
  );
}

export function CashflowSectionRows({ children }: { children: ReactNode }) {
  const { isExpanded } = useCashflowSection();
  return isExpanded ? <>{children}</> : null;
}

export function CashflowSectionRow({ children }: { children: ReactNode }) {
  return <TableRow>{children}</TableRow>;
}

export function CashflowSectionRowLabel({
  children,
  bold = false,
  interactive = false,
  onClick,
  tooltip,
}: {
  children: ReactNode;
  bold?: boolean;
  interactive?: boolean;
  onClick?: () => void;
  tooltip?: ReactNode;
}) {
  const cell = (
    <TableCell
      onClick={onClick}
      sx={{
        backgroundColor: "background.paper",
        borderRight: 1,
        borderRightColor: "custom.borderSecondary",
        fontWeight: bold ? 600 : 400,
        width: cashflowLayoutConfig.labelColumnWidth,
        minWidth: cashflowLayoutConfig.labelColumnWidth,
        maxWidth: cashflowLayoutConfig.labelColumnWidth,
        boxSizing: "border-box",
        cursor: interactive ? "pointer" : undefined,
      }}
    >
      {children}
    </TableCell>
  );
  return tooltip ? <Tooltip title={tooltip}>{cell}</Tooltip> : cell;
}

export function CashflowSectionValueCell({
  value,
  currency,
  columnIndex,
  dateFrom,
  isBold = false,
  colorMode = "none",
  balanceQuality,
  onClick,
  children,
}: {
  value?: number | null;
  currency?: string;
  columnIndex?: number;
  dateFrom?: string;
  isBold?: boolean;
  colorMode?: CashflowTableValueColorMode;
  balanceQuality?: BalanceQuality | null;
  onClick?: () => void;
  children?: ReactNode;
}) {
  const isHighlighted = useIsColumnSelected(columnIndex ?? 0);
  const { setPeriod } = useTimePeriodControls();
  const handleClick = onClick ?? (dateFrom ? () => setPeriod(dayjs(dateFrom)) : undefined);
  return (
    <TableCell
      onClick={handleClick}
      aria-selected={isHighlighted}
      sx={{
        textAlign: "right",
        cursor: "pointer",
        backgroundColor: "background.paper",
        borderBottom: isHighlighted ? "none" : undefined,
        borderRight: 1,
        borderRightColor: isHighlighted ? "custom.borderSecondary" : "background.paper",
        borderLeft: 1,
        borderLeftColor: isHighlighted ? "custom.borderSecondary" : "background.paper",
        fontWeight: isBold ? 600 : 400,
        color: "text.primary",
        boxSizing: "border-box",
      }}
    >
      <Box sx={{ minHeight: 24, display: "flex", alignItems: "center", justifyContent: "flex-end", gap: 0.5, width: "100%", whiteSpace: "nowrap" }}>
        {children ?? (value !== null && value !== undefined ? <><CashflowQualityIndicator balanceQuality={balanceQuality} size="sm" variant="icon" />{currency ? <CurrencyAmount notation="compact" value={value} currency={currency} naturalPrecision /> : value}</> : null)}
      </Box>
    </TableCell>
  );
}

import { IconArrowDownRight, IconArrowUpRight } from "@dfp/react-icons";

import { useTT } from "../../useTT.ts";
import { CashflowTableValueCell } from "./CashflowTableCell.tsx";
import {
  CashflowSection,
  CashflowSectionHeader,
  CashflowSectionHeaderIcon,
  CashflowSectionHeaderTitle,
  CashflowSectionRows,
  CashflowSectionTrigger,
  CashflowSectionValueCell,
  CashflowCategoryDataRow,
  useCashflowTable,
} from "./components/index.ts";
import type { CategoryType } from "./types/index.ts";

type CashflowTableCategorySectionProps = {
  variant: "income" | "costs";
};

const sectionPresets = {
  income: {
    titleKey: "cashflowTable.rows.income" as const,
    icon: IconArrowUpRight,
    iconColor: "success.main",
    categoryType: "income" as const,
    direction: "IN" as const,
    totalSelector: (period: { income: number }) => period.income,
    filterSelector: (categoryFilter: { income: CategoryType[] }) => categoryFilter.income,
  },
  costs: {
    titleKey: "cashflowTable.rows.costs" as const,
    icon: IconArrowDownRight,
    iconColor: "error.main",
    categoryType: "costs" as const,
    direction: "OUT" as const,
    totalSelector: (period: { costs: number }) => period.costs,
    filterSelector: (categoryFilter: { costs: CategoryType[] }) => categoryFilter.costs,
  },
};

export function CashflowTableCategorySection({ variant }: CashflowTableCategorySectionProps) {
  const { data, categoryFilter, allCategories } = useCashflowTable();
  const { tt } = useTT();
  const preset = sectionPresets[variant];
  const Icon = preset.icon;

  return (
    <CashflowSection>
      <CashflowSectionHeader>
        <CashflowSectionHeaderTitle>
          <CashflowSectionHeaderIcon sx={{ color: preset.iconColor }}>
            <Icon />
          </CashflowSectionHeaderIcon>
          {tt(preset.titleKey)}
          <CashflowSectionTrigger categoryType={preset.categoryType} />
        </CashflowSectionHeaderTitle>

        {data?.periods.map((period, index) => (
          <CashflowTableValueCell key={period.id} value={preset.totalSelector(period)} columnIndex={index} dateFrom={period.dateFrom} isBold />
        ))}
      </CashflowSectionHeader>

      <CashflowSectionRows>
        {preset.filterSelector(categoryFilter).map((category: CategoryType) => (
          <CashflowCategoryDataRow key={category} allCategories={allCategories} category={category} direction={preset.direction} />
        ))}
      </CashflowSectionRows>
    </CashflowSection>
  );
}

