};
const CashflowSectionContext =
  createContext<CashflowSectionContextValue | null>(null);
function useCashflowSection() {
  const value = useContext(CashflowSectionContext);
  if (!value) throw new Error("CashflowSectionContext is missing");
  return value;
}

export function CashflowSection({
  children,
  defaultExpanded = true,
}: {
  children: ReactNode;
  defaultExpanded?: boolean;
}) {
  const [isExpanded, setIsExpanded] = useState(defaultExpanded);
